@using sv_a12e0a4cafa54b95a5724fbb58b92557.Models

<nav aria-label="Application steps" class="mb-4">
    <div class="d-flex justify-content-between position-relative">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var isClickable = isCompleted && !isCurrent;

            <div class="text-center flex-fill">
                <button type="button"
