+            var isClickable = isCompleted && !isCurrent;
+
+            <div class="text-center flex-fill">
+                <button type="button"
+                        class="btn rounded-circle @GetCircleClass(step) mb-1"
+                        style="width: 36px; height: 36px; font-size: 0.85rem;"
+                        disabled="@(!isClickable)"
+                        @onclick="() => OnStepClicked.InvokeAsync(step)">
+                    @if (isCompleted && !isCurrent)
+                    {
+                        <span>&#10003;</span>
+                    }
+                    else
+                    {
+                        @step
+                    }
+                </button>
+                <div class="small @(isCurrent ? "fw-bold text-primary" : isCompleted ? "text-success" : "text-muted")">
+                    @StepNames[i]
+                </div>
+            </div>
+        }
+    </div>
+</nav>
+
+@code {
+    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
+
+    [Parameter, EditorRequired] public int CurrentStep { get; set; }
+    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
+    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
+
+    private string GetCircleClass(int step)
+    {
+        if (step == CurrentStep) return "btn-primary";
+        if (CompletedSteps.Contains(step)) return "btn-success";
+        return "btn-outline-secondary";
+    }
+}
+

