+
+    private void AddReference()
+    {
+        if (References.Count < 3)
+            References.Add(new ReferenceModel());
+    }
+
+    private void RemoveReference(int index)
+    {
+        if (References.Count > 1)
+            References.RemoveAt(index);
+    }
+
+    private async Task HandleNext()
+    {
+        ErrorMessage = null;
+
+        if (References.Count < 2)
+        {
+            ErrorMessage = "Please provide at least 2 references.";
+            return;
+        }
+
+        if (!References.All(r => r.IsValid()))
+        {
+            ErrorMessage = "Please fill in all fields for each reference.";
+            return;
+        }
+
+        await OnNext.InvokeAsync();
+    }
